export const 鎮宅伏尸 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    const 桿 = (x0, x1, z) => {
        線(p => p.M(X(x0) + 0.32 * k, Z(z)).L(X(x1) - 0.32 * k, Z(z)));
        圈(x0, z);
        圈(x1, z);
    };
    // 符頭：桿二＋側圈＋日口小箱對（帶中杙）
    桿(0.5, 7.4, 1.0);
    桿(0.5, 7.4, 2.4);
    圈(0.5, 3.7);
    圈(7.2, 3.6);
    圈(0.5, 5.2);
    線(p => p.M(X(1.7), Z(4.5)).L(X(1.7), Z(6.4)).L(X(3.7), Z(6.35))
        .L(X(3.7), Z(4.45)).L(X(1.65), Z(4.5)));
    線(p => p.M(X(1.8), Z(5.45)).L(X(3.6), Z(5.4)), 0.34);
    線(p => p.M(X(2.7), Z(3.9)).L(X(2.7), Z(4.5)), 0.34);
    線(p => p.M(X(4.4), Z(4.5)).L(X(4.4), Z(6.3)).L(X(6.2), Z(6.25))
        .L(X(6.2), Z(4.45)).L(X(4.35), Z(4.5)));
    線(p => p.M(X(5.3), Z(3.9)).L(X(5.3), Z(4.5)), 0.34);
    // 寬桁匣
    線(p => p.M(X(0.6), Z(7.0)).L(X(7.3), Z(6.9)), 0.42);
    線(p => p.M(X(1.6), Z(7.8)).L(X(1.6), Z(10.3)).L(X(5.9), Z(10.25))
        .L(X(5.9), Z(7.75)).L(X(1.55), Z(7.8)));
    線(p => p.M(X(1.7), Z(9.0)).L(X(5.8), Z(8.95)));
    線(p => p.M(X(0.9), Z(8.4)).L(X(1.6), Z(8.35)), 0.34);
    線(p => p.M(X(0.7), Z(10.7)).L(X(7.2), Z(10.6)), 0.42);
    // 環鏈大圈足二串（各三環相銜）
    const 環串 = (cx) => 線(p => p.M(X(cx + 0.9), Z(11.2))
        .C(X(cx - 1.2), Z(11.4), X(cx - 1.2), Z(13.0), X(cx + 0.3), Z(13.1))
        .C(X(cx + 1.6), Z(13.2), X(cx + 1.5), Z(14.6), X(cx + 0.2), Z(14.8))
        .C(X(cx - 1.3), Z(15.0), X(cx - 1.3), Z(16.5), X(cx + 0.2), Z(16.6))
        .C(X(cx + 1.2), Z(16.7), X(cx + 1.4), Z(17.4), X(cx + 0.8), Z(17.9)));
    環串(2.2);
    環串(5.4);
};
